static inline int get_pages_cpu(struct page *page) {
    return (page - pagemeta_start) / PAGES_PER_CPU;
}

static inline uint64 page_to_pa(struct page *page) {
    return (page - pagemeta_start) * PGSIZE + START_MEM;
}
static struct page *pa_to_page(uint64 pa) {
    ASSERT((pa - START_MEM) % PGSIZE == 0);
    return ((pa - START_MEM) / PGSIZE + pagemeta_start);
}

struct run {
  struct run *next;
};

struct {
  struct spinlock lock;
  struct run *freelist;
  uint64 npage;
} kmem;

struct page *steal_mem(int cur_id, uint64 order) {
    struct page *page = NULL;
    for (int i = 0; i < NCPU; i++) {
        if (i == cur_id) {
            continue;
        }
        // TODO
        push_off();
        page = buddy_get_pages(&mempools[i], order);
        if (page != NULL) {
            return page;
        }
    }
    ASSERT(page == NULL);
    return page;
}

uint64 size_to_page_order(uint64 size) {
    uint64 order;
    uint64 page_num;
    uint64 tmp;

    order = 0;
    page_num = ROUND_UP(size, PGSIZE) / PGSIZE;
    tmp = page_num;

    while (tmp > 1) {
        tmp >>= 1;
        order += 1;
    }

    if (page_num > (1 << order)) {
        order += 1;
    }

    return order;
}

void
kinit()
{
  initlock(&kmem.lock, "kmem");
  kmem.freelist = 0;
  kmem.npage = 0;
  freerange(kernel_end, (void*)PHYSTOP);
  #ifdef DEBUG
  printf("kernel_end: %p, phystop: %p\n", kernel_end, (void*)PHYSTOP);
  printf("kinit\n");
  #endif
}

void
freerange(void *pa_start, void *pa_end)
{
  char *p;
  p = (char*)PGROUNDUP((uint64)pa_start);
  for(; p + PGSIZE <= (char*)pa_end; p += PGSIZE)
    kfree(p);
}

// Free the page of physical memory pointed at by v,
// which normally should have been returned by a
// call to kalloc().  (The exception is when
// initializing the allocator; see kinit above.)
// void
// kfree(void *pa)
// {
//   struct run *r;

//   if(((uint64)pa % PGSIZE) != 0 || (char*)pa < kernel_end || (uint64)pa >= PHYSTOP)
//     panic("kfree");

//   // Fill with junk to catch dangling refs.
//   memset(pa, 1, PGSIZE);

//   r = (struct run*)pa;

//   acquire(&kmem.lock);
//   r->next = kmem.freelist;
//   kmem.freelist = r;
//   kmem.npage++;
//   release(&kmem.lock);
// }
void kfree(void *pa) {
    struct page *page = pa_to_page((uint64)pa);
    acquire(&page->lock);
    ASSERT(page->count >= 1);
    page->count--;
    if (page->count >= 1) {
        release(&page->lock);
        return;
    }
    ASSERT(page->count == 0);
    release(&page->lock);

    ASSERT(page->allocated == 1);
    int id = get_pages_cpu(page);
    ASSERT(id >= 0 && id < NCPU);
    buddy_free_pages(&mempools[id], page);
}


// Allocate one 4096-byte page of physical memory.
// Returns a pointer that the kernel can use.
// Returns 0 if the memory cannot be allocated.
// void *
// kalloc(void)
// {
//   struct run *r;

//   acquire(&kmem.lock);
//   r = kmem.freelist;
//   if(r) {
//     kmem.freelist = r->next;
//     kmem.npage--;
//   }
//   release(&kmem.lock);

//   if(r)
//     memset((char*)r, 5, PGSIZE); // fill with junk
//   // else
//   //   printf("[kalloc]: can not alloc!\n");
//   return (void*)r;
// }
void *kalloc(void) {
    int order = 0;

    push_off();
    int id = cpuid();
    ASSERT(id >= 0 && id < NCPU);
    struct page *page = buddy_get_pages(&mempools[id], order);

    if (page == NULL) {
        page = steal_mem(id, order);
        if (page == NULL) {
            return 0;
        }
    }

    acquire(&page->lock);
    ASSERT(page->count == 0);
    page->count = 1;
    release(&page->lock);
    return (void *)page_to_pa(page);
}


