    return -1;
  return wait(p);
}

uint64
sys_waitpid(void)
{
  int pid, options;
  uint64 status;
  if(argint(0,&pid) < 0 || argaddr(1,&status) < 0 || argint(2,&options) < 0)
    return -1;
  return waitpid(pid, status, options);
}

uint64
sys_clone(void)
{
  int flag;
  uint64 stack;
  if(argint(0, &flag) < 0 || argaddr(1, &stack) < 0){
    #ifdef DEBUG
      //printf("error\n");
    #endif
    return -1;
  }
  #ifdef DEBUG
  //printf("entering clone\n");
  #endif
  return clone(flag, stack);
}

uint64
sys_sbrk(void)
{
  int addr;
  int n;

  if(argint(0, &n) < 0)
    return -1;
  addr = myproc()->sz;
  if(growproc(n) < 0)
    return -1;
  return addr;
}

uint64
sys_sleep(void)
{
  int n;
  uint ticks0;

  if(argint(0, &n) < 0)
    return -1;
  acquire(&tickslock);
  ticks0 = ticks;
  while(ticks - ticks0 < n){
    if(myproc()->killed){
      release(&tickslock);
      return -1;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);
  return 0;
}

uint64
sys_kill(void)
{
  int pid;

  if(argint(0, &pid) < 0)
    return -1;
  return kill(pid);
}

// return how many clock tick interrupts have occurred
// since start.
uint64
sys_uptime(void)
{
  uint xticks;

  acquire(&tickslock);
