uint64 
sys_rt_sigprocmask(void){
  int how;
    uint64 uptr_set, uptr_oldset;

    __sigset_t set, oldset;

    argint(0, &how);
    argaddr(1, &uptr_set);
    argaddr(2, &uptr_oldset);

    if (uptr_set && copyin(myproc()->pagetable, (char*)&set, uptr_set, SIGSET_LEN * 8) < 0) {
        return -1;
    }

    if (sigprocmask(how, &set, uptr_oldset ? &oldset : NULL)) {
        return -1;
    }

    if (uptr_oldset && copyout(myproc()->pagetable, uptr_oldset, (char*)&oldset, SIGSET_LEN * 8) < 0) {
        return -1;
    }
    //printf("sys_rt_sigprocmask: how = %d, set = %p\n", how, set.__val[0]);
    return 0;

}

