  if(argfd(0, &oldfd, &f) < 0 ||  argint(1, &newfd) < 0)
    return -1;

  // printf("[sys_dup2] oldfd: %d, newfd: %d\n", oldfd, newfd);

  if(oldfd == newfd)
    return newfd;

  if (newfd < 0 || newfd >= NOFILE)
    return -1;

  fileclose(p->ofile[newfd]);
  p->ofile[newfd] = f;

  filedup(f);
  return newfd;
}

