uint64
sys_brk(void)
{
  uint64 addr;
  uint64 n;

  if(argaddr(0, &n) < 0)
    return -1;

  addr = myproc()->sz;
  if (n == 0)
  {
    return addr;
  }
  if (n >= addr)
  {
    if(growproc(n - addr) < 0)
      return -1;
    else return myproc()->sz;
  }
