uint64
sys_mmap(void)
{
  uint64 start, len, off;
  int prot, flags, fd;

  argaddr(0, &start);
  argaddr(1, &len);
  argint(2, &prot);
  argint(3, &flags);
  argint(4, &fd);
  argaddr(5, &off);

  // Filter invalid args before doing mmap.

  if (off < 0 || off % PGSIZE != 0 || len <= 0)
    return -1;

  if (!(flags & (MAP_SHARED | MAP_PRIVATE)))
    return -1;

  if (!start && (flags & MAP_FIXED))
    return -1;

  if (fd < 0 || fd > NOFILE)
    return -1;

  if (!fd && (flags & MAP_ANONYMOUS))
    return -1;

  return do_mmap(start, len, prot, flags, fd, off);
}

