uint64
sys_nanosleep(void)
{
  uint64 req_addr, rem_addr;
  argaddr(0, &req_addr);
  argaddr(1, &rem_addr);

  struct timeval req_time, rem_time;
  if (copyin2((char*)&req_time, req_addr, sizeof(req_time)) < 0)
    return -1;
  if (copyin2((char*)&rem_time, rem_addr, sizeof(rem_time)) < 0)
    return -1;

  uint64 n = req_time.tv_sec;

  acquire(&tickslock);
  uint ticks0 = ticks;
  while(ticks - ticks0 < n){
    if(myproc()->killed){
      release(&tickslock);
      return -1;
    }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);

  return 0;
}

