  if(clockid == CLOCK_REALTIME){
    struct timespec tspc;
    uint64 tstamp = r_time();
    tspc.tv_sec = tstamp / CLK_FRQ;
    tspc.tv_nsec =(tstamp % CLK_FRQ) * (1000000000 / CLK_FRQ);
    if (copyout2((uint64)tp, (char*)&tspc, sizeof(tspc)) < 0)
      return -1;
  }else{
    return -1;
  }

  return 0;
}

