// Load a program segment into pagetable at virtual address va.
// va must be page-aligned
// and the pages from va to va+sz must already be mapped.
// Returns 0 on success, -1 on failure.
static int
loadseg(pagetable_t pagetable, uint64 va, struct ext4_file *f, uint offset, uint sz)
{
  uint i, n;
  int rcnt;
  uint64 pa;
  if((va % PGSIZE) != 0)
    panic("loadseg: va must be page aligned");

  for(i = 0; i < sz; i += PGSIZE){
    pa = walkaddr(pagetable, va + i);
    if(pa == NULL)
      panic("loadseg: address should exist");
    if(sz - i < PGSIZE)
      n = sz - i;
    else
      n = PGSIZE;

    // printf("pa: %p, offset+i: %p, n: %d\n", pa, offset+i, n);

    // printf("fpos: %p\n", f->fpos);
    if(EXT4read(f, pa, offset + i, n, &rcnt))
      return -1;
    if(rcnt != n)
      return -1;
  }

  return 0;
}


