// Read from file f.
// addr is a user virtual address.
// Read from file f.
// addr is a user virtual address.
int
fileread(struct file *f, uint64 addr, int n)
{
  int r = 0, rcnt = 0;

  if(f->readable == 0)
    return -1;

  switch (f->type) {
    case FD_PIPE:
      rcnt = piperead(f->pipe, addr, n);
      break;
    case FD_DEVICE:
      if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read)
        return -1;
      rcnt = devsw[f->major].read(1, addr, n);
      break;
    case FD_ENTRY:
      if((r = EXT4read(f->file, addr, f->off, n, &rcnt)) == EOK)
        f->off += rcnt;
      break;
    default:
      if(f->type == 9)
        return 0;
      panic("fileread");
  }

  return rcnt;
}

// Write to file f.
// addr is a user virtual address.
int
filewrite(struct file *f, uint64 addr, int n, int user_source)
{
  // printf("[filewrite] file: %p, off: %p, type: %d, addr: %p, n: %d\n", f->file, f->off, f->type, addr, n);
  int ret = 0, wcnt = 0;

  if(f->writable == 0)
    return -1;

  if(f->type == FD_PIPE){
    ret = pipewrite(f->pipe, addr, n, user_source);
  } else if(f->type == FD_DEVICE){
    if(f->major < 0 || f->major >= NDEV || !devsw[f->major].write)
      return -1;
    // printf("[filewrite] major: %d\n", f->major);
    ret = devsw[f->major].write(user_source, addr, n);
  } else if(f->type == FD_ENTRY){

    if (EXT4write(f->file, addr, f->off, n, &wcnt) == EOK) {
      ret = wcnt;
      f->off += wcnt;
    } else {
      ret = -1;
    }

  } else {
    panic("filewrite");
  }

  // printf("[filewrite] ret: %d\n", ret);
  return ret;
}

// Read from dir f.
// addr is a user virtual address.
int
filewritev(struct file *f, struct iovec iov[], int iovcnt)
{
  int ret = 0;
  struct ext4_file *file;

	if (!f->writable)
		return -1;
	switch (f->type) {
		case FD_PIPE:
			ret = pipewritev(f->pipe, iov, iovcnt);
			break;
		case FD_DEVICE:
      file = f->file;
			ret = devsw[f->major].writev(1, iov, iovcnt);
			break;
		case FD_ENTRY:
      file = f->file;
			ret = fwritev(file, iov, iovcnt, f->off);
			if (ret > 0) {
				f->off += ret;
			}
			break;
		default:
			panic("filewritev");
	}
	return ret;
}

int
filereadv(struct file *f, struct iovec iov[], int iovcnt)
{
  int ret = 0;
  struct ext4_file *file;

	if (!f->readable)
		return -1;

	switch (f->type) {
		case FD_PIPE:
			ret = pipereadv(f->pipe, iov, iovcnt);
			break;
		case FD_DEVICE:
      file = f->file;
			ret = devsw[f->major].readv(1, iov, iovcnt);
			break;
		case FD_ENTRY:
      file = f->file;
			ret = freadv(file, iov, iovcnt, f->off);
			if (ret > 0) {
				f->off += ret;
			}
			break;
		default:
			panic("filereadv");
	}
	return ret;
}

int
direntnext(struct file *f, uint64 buf, int len)
{
  // printf("[direntnext] buf: %p, len: %d\n", buf, len);
  if(f->readable == 0)
    return -1;

  uint64 nread = len;

  struct linux_dirent64* de64 = (struct linux_dirent64*)buf;
  struct ext4_dir *dir = f->dir;
  const struct ext4_direntry *dentry = NULL;

  if(f->type == FD_ENTRY) {
    while ((dentry = ext4_dir_entry_next(dir))) {
		  if (!dentry->inode) 
			  continue;

      de64->d_ino = (uint64)dentry->inode;
      de64->d_off = dir->next_off;
      de64->d_type = dentry->inode_type;
      copyout2((uint64)de64->d_name, (char*)dentry->name, dentry->name_length + 1);

      int size = ((uint64)de64->d_name - (uint64)de64) + dentry->name_length + 1;
      size += (sizeof(uint64) - (size % sizeof(uint64))) % sizeof(uint64);
      de64->d_reclen = size;

      // printf("[direntnext] de64: %p, size: %d, de64name: %s, length: %d\n", (uint64)de64, size, (char*)de64->d_name, dentry->name_length);

      // buff overflow
      if(size > len) {
        // printf("[direntnext] buff overflow\n");
        break;
      }

      // if(copyout2(buf, (char*)&de64, size) < 0) {
      //   return -1;
      // }

      de64 = (struct linux_dirent64*)((uint64)de64 + size);
      len -= size;
	  }
	  // ext4_dir_entry_rewind(dir);
  }

  return nread - len;
}

void
fd_set_exec_flag(struct file *f, int fd, int flag)
{
  if(flag) {
    if(fd < 64)
      f->flagslow |= (1 << fd);
    else
      f->flagshigh |= (1 << (fd % 64));
  } else {
    if(fd < 64)
      f->flagslow &= ~(1 << fd);
    else
      f->flagshigh &= ~(1 << (fd % 64));
  }
}

int
fd_get_exec_flag(struct file *f, int fd)
{
  if(fd < 64)
    return f->flagslow & (1 << fd);
  else
    return f->flagshigh & (1 << (fd % 64));
}


int
is_relative(const char *path)
{
  if(path[0] == '.' || path[0] != '/')
    return 1;
  else
    return 0;
}

char*
to_abspath(char *path)
{
  //cannot infer cwd from dir? pcb change may required
  while(*path == '.')
    path++;
  if(*path == '\0'){
    strcat(path, "/", 0);
  }
  else if(*path != '/'){
    char temp[MAXPATH];
    strcpy(temp, path);
    *path = '/';
    strcpy(path + 1, temp);
  }
  return path;
}

