int ext4_init()
{
    const char* mount_point = "/";
    int r;

    struct ext4_blockdev *blockdev = ext4_blockdev_get();
    r = ext4_device_register(blockdev, "ext4_bd");
    if (r != EOK) {
        printf("[ext4] device register error! r=%d\n", r);
        return -1;
    }
    printf("[ext4] device register success!\n");

    r = ext4_mount("ext4_bd", mount_point, false);
    if (r != EOK) {
        printf("[ext4] mount error! r=%d\n", r);
        return -1;
    }
    printf("[ext4] mount success!\n");

    r = ext4_recover(mount_point);
    if (r != EOK && r != ENOTSUP) {
        printf("[ext4] recover error! r=%d\n", r);
        return -1;
    }
    printf("[ext4] recover success!\n");

    r = ext4_journal_start(mount_point);
    if (r != EOK) {
        printf("[ext4] journal start error! r=%d\n", r);
        return -1;
    }
    printf("[ext4] journal start success!\n");

    r = ext4_cache_write_back(mount_point, true);
    if (r != EOK) {
        printf("[ext4] cache write back error! r=%d\n", r);
        return -1;
    }
    printf("[ext4] cache write back success!\n");

    return 0;
}

void EXT4lock(struct ext4_file *f)
{
    // if (!f) 
    //     panic("EXT4lock");
    acquiresleep(&f->lock);
}

void EXT4unlock(struct ext4_file *f)
{
    // if (f == 0 || !holdingsleep(&f->lock))
    //     panic("EXT4unlock");
    releasesleep(&f->lock);
}

void EXT4put(struct ext4_file *f)
{
    return;
}

static char *get_name(char *s, const struct ext4_direntry *entry)
{
	memcpy(s, entry->name, entry->name_length);
	s[entry->name_length] = 0;
	return s;
}

int readdir(const char *path)
{
	char name_buf[255];
	const struct ext4_direntry *dentry = NULL;
    ext4_dir *d = dir_open(path);
    if (d == NULL) {
        printf("readdir: can't open path %s\n", path);
        return -1;
    }

	while ((dentry = ext4_dir_entry_next(d))) {
		if (!dentry->inode) 
			continue;
		printf("%s\n",get_name(name_buf, dentry));
	}
	ext4_dir_entry_rewind(d);
    return 0;
}

struct ext4_file *fname(char *path)
{
    struct ext4_file *f = (ext4_file*)kmalloc(sizeof(ext4_file));

    char name_buf[255];
    name_buf[0] = '/';
    strcpy(name_buf + 1, path);

    int r;
    if((r = EXT4open(f, name_buf, O_RDONLY)) != EOK) {
        printf("EXT4: open error!\n");
        return NULL;
    }

    return f;
}

int EXT4seek(struct ext4_file *file, uint off, uint origin)
{
    return ext4_fseek(file, off, origin);
}

int EXT4read(struct ext4_file *file, uint64 buf, uint off, uint size, int *rcnt)
{
    int r = EOK;
    r = EXT4seek(file, off, SEEK_SET);
    if (r != EOK) {
        printf("EXT4: seek error!\n");
        return -1;
    }
    return ext4_fread(file, (void*)buf, (size_t)size, (size_t*)rcnt);
}

int EXT4write(struct ext4_file *file, uint64 buf, uint off, uint size, int *wcnt)
{
    int r = EOK;
    r = EXT4seek(file, off, SEEK_SET);
    if (r != EOK) {
        printf("seek error!\n");
        return -1;
    }
    return ext4_fwrite(file, (void*)buf, (size_t)size, (size_t*)wcnt);
}

int EXT4open(struct ext4_file *file, const char *path, uint32_t flags)
{
    // 将 fflag 转换为 oflag
    uint32_t oflag = 0;
    if (flags & O_RDONLY)
        oflag |= O_RDONLY;
    if (flags & O_WRONLY)
        oflag |= O_WRONLY;
    if (flags & O_RDWR)
        oflag |= O_RDWR;
    if (flags & O_APPEND)
        oflag |= O_APPEND;
    if (flags & O_CREATE)
        oflag |= O_CREAT;
    if (flags & O_TRUNC)
        oflag |= O_TRUNC;

    // 调用 ext4_fopen2 函数
    int r = ext4_fopen2(file, path, oflag);
    if (r != EOK) {
        printf("fopen error!\n");
        return -1;
    }
    return r;
}

int EXT4close(struct ext4_file *file)
{
    int r = ext4_fclose(file);
    if (r != EOK) {
        printf("fclose error!\n");
        return -1;
    }
    kmfree(file);
    return r;
}

struct ext4_dir *dir_open(const char *path)
{
    ext4_dir *d = (ext4_dir*)kmalloc(sizeof(ext4_dir));
    if (d == NULL) {
        kmfree(d);
        return NULL;
    }
    int r;
    if((r = ext4_dir_open(d, path)) != EOK) {
        kmfree(d);
        return NULL;
    }

    return d;
}

int funlink(const char *path)
{
  int r = ext4_fremove(path);
  return r;
}

int fwritev(struct ext4_file *f, struct iovec iov[], int iovcnt, uint off)
{
    int r, rcnt;
	uint tot = 0;
	for (int i = 0; i < iovcnt; i++) {
		uint64 buf = (uint64)iov[i].iov_base;
		uint n = iov[i].iov_len;

		if((r = EXT4write(f, buf, off + tot, n, &rcnt)) != EOK || rcnt != n) {
            return -1;
        }
		tot += rcnt;
	}
	return tot;
}
int freadv(struct ext4_file *file, struct iovec iov[], int iovcnt, uint off)
{
    int r, rcnt;
	uint tot = 0;
	for (int i = 0; i < iovcnt; i++) {
		uint64 buf = (uint64)iov[i].iov_base;
		uint n = iov[i].iov_len;

		if((r = EXT4read(file, buf, off + tot, n, &rcnt)) != EOK || rcnt != n) {
            return -1;
        }
		tot += rcnt;
	}
	return tot;
}
struct ext4_inode_ref *file_get_inode_ref(struct ext4_file *file)
{
    struct ext4_inode_ref *ref = NULL;
    int r;
    if((r = ext4_file_get_inode_ref(file, ref)) != EOK)
        printf("ext4_fs_get_inode_ref error!\n");
    return ref;
}

uint32 get_inode_type(struct ext4_file *file)
{
    struct ext4_inode_ref *ref = file_get_inode_ref(file);
    if(ref == NULL){
        return 0;
    }
    return ext4_inode_type(&ref->fs->sb, ref->inode);
}

int mkdir(const char *path)
{
    int r = ext4_dir_mk(path);
    if(r != EOK) {
        printf("mkdir error!\n");
        return -1;
    }
    return r;
}

