static int blockdev_bread(struct ext4_blockdev *bdev, void *buf, uint64_t blk_id,
			 uint32_t blk_cnt)
{
	// printf("bread!\n");
	uint64 buf_ptr = (uint64)buf;
	for(int i = 0; i < blk_cnt; i++) {
		// printf("blk_id: %d, blk_cnt: %d\n", blk_id + i, blk_cnt);
		struct buf *b = bread(0, blk_id + i);
		memmove((void*)buf_ptr, b->data, BLOCK_SIZE);
		buf_ptr += BLOCK_SIZE;
		brelse(b);
	}

	// struct ext4_sblock *sb;
	// sb = (struct ext4_sblock*)buf;
	// printf("blocks_count: %d\n", sb->blocks_count_lo);

	// printf("bread ok!\n");
	return EOK;
}

/******************************************************************************/
static int blockdev_bwrite(struct ext4_blockdev *bdev, const void *buf,
			  uint64_t blk_id, uint32_t blk_cnt)
{
	//printf("bwrite!\n");
	uint64 buf_ptr = (uint64)buf;
	for(int i = 0; i < blk_cnt; i++) {
		struct buf *b = bget(0, blk_id + i);
		memmove(b->data, (void*)buf_ptr, BLOCK_SIZE);
		buf_ptr += BLOCK_SIZE;
		brelse(b);
	}

	//printf("bwrite ok!\n");
	return EOK;
}
